package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        // Create a new CSVFormat instance with nullString = null using withNullString method
        CSVFormat format = CSVFormat.DEFAULT.withNullString(null);

        assertFalse(format.isNullStringSet());
    }

    @Test
    public void testIsNullStringSet_whenNullStringIsNotNull() throws Exception {
        // Create a new CSVFormat instance with nullString = "NULL" using withNullString method
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");

        assertTrue(format.isNullStringSet());
    }
}
